/* --- Designflow Ultra-Dense Redesign --- */
.add-product-container {
  display: flex;
  flex-direction: column;
  width: 100%;
  max-width: 1350px;
  background: #ffffff;
  overflow: hidden;
  max-height: 90vh;
  /* Fixed height to avoid scroll */

  &.duplicated-mode {
    border: 2px solid #D81B60;
  }
}

.modal-header-branded,
.modal-footer-branded {
  flex-shrink: 0;
  background-color: #f8f9fa;
  padding: 12px 24px;
  border-bottom: 1px solid #e9ecef;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.modal-footer-branded {
  border-bottom: none;
  border-top: 1px solid #e9ecef;
  justify-content: flex-end;
  gap: 12px;
}

.modal-content-dense {
  padding: 16px 24px;
  flex-grow: 1;
  overflow: scroll;
}

.dense-grid {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 12px;

  .col-4 {
    grid-column: span 4;
  }

  .col-2 {
    grid-column: span 2;
  }

  .col-1 {
    grid-column: span 1;
  }
}

/* Height optimization to remove scroll */
::ng-deep .mat-mdc-form-field-subscript-wrapper {
  display: none !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  height: 48px !important;
  background: #fff !important;
}

/* Bottom Preview Logic: Appears below the grid */
.bottom-preview-row {
  margin-top: 12px;
  padding: 8px 16px;
  background: rgba(216, 27, 96, 0.03);
  border: 1px dashed #D81B60;
  border-radius: 8px;

  .preview-content {
    display: flex;
    align-items: center;
    gap: 16px;

    img {
      height: 50px;
      width: 50px;
      object-fit: contain;
      border-radius: 4px;
      background: #fff;
      border: 1px solid #eee;
    }

    .preview-info {
      flex-grow: 1;
      display: flex;
      flex-direction: column;
    }

    .preview-label {
      font-size: 11px;
      font-weight: 700;
      color: #D81B60;
      text-transform: uppercase;
    }

    .preview-sub {
      font-size: 13px;
      color: #1a202e;
      font-weight: 500;
    }
  }
}

/* Enabled state only */
.save-btn:not(.mat-mdc-button-disabled) {
  background-color: #D81B60;
  color: #fff;
}

/* Disabled state (MDC) */
.save-btn.mat-mdc-button-disabled,
.save-btn[disabled] {
  background-color: #e0e0e0 !important;
  color: #9e9e9e !important;
  cursor: not-allowed;
  opacity: 0.75;
}

/* Optional: icon color when disabled */
.save-btn.mat-mdc-button-disabled mat-icon {
  color: #9e9e9e !important;
}


.upload-trigger-btn {
  height: 48px;
  width: 100%;
  border-color: #cfd8dc;
  color: #37474f;
  font-weight: 500;
}

.utility-cell {
  display: flex;
  align-items: center;
}

/* RFQ Search Stylings */
.rfq-search-row {
  display: flex;
  align-items: center;
  padding: 8px 16px;
  gap: 12px;
  background: #fff;
  border-bottom: 1px solid #e0e0e0;
  position: sticky;
  top: 0;
  z-index: 10;

  .inner-search {
    flex: 1;
    border: 1px solid #ddd;
    padding: 8px 12px;
    border-radius: 4px;
    font-size: 14px;
    outline: none;

    &:focus {
      border-color: #D81B60;
    }
  }

  mat-checkbox {
    font-size: 13px;
  }
}

.add-new-inline {
  display: flex;
  align-items: center;
  padding: 8px 16px;
  gap: 12px;
  background: #f9f9f9;
  border-bottom: 1px solid #e0e0e0;

  input {
    flex: 1;
    border: 1px solid #ddd;
    padding: 8px 12px;
    border-radius: 4px;
    font-size: 14px;
    outline: none;

    &:focus {
      border-color: #D81B60;
    }
  }

  button {
    color: #D81B60;
    font-weight: 500;
  }
}

