+import { describe, expect, it, jest, beforeEach } from '@jest/globals';
+import { of } from 'rxjs';
+import { HttpClient } from '@angular/common/http';
+import { ItemDetailService } from './item_detail.service';
+
+function makeHttp(overrides: Partial<Pick<HttpClient, 'get' | 'post' | 'delete'>> = {}): HttpClient {
+  return {
+    get: jest.fn(),
+    post: jest.fn(),
+    delete: jest.fn(),
+    ...overrides,
+  } as unknown as HttpClient;
+}
+
+describe('ItemDetailService product assignments', () => {
+  let http: HttpClient;
+  let service: ItemDetailService;
+
+  beforeEach(() => {
+    localStorage.clear();
+    http = makeHttp();
+    service = new ItemDetailService(http as any);
+  });
+
+  it('gets product assignments for an item', () => {
+    (http.get as jest.Mock).mockReturnValue(of({ status: true, roles: [], data: [] }));
+
+    service.getProductAssignments(42);
+
+    expect(http.get).toHaveBeenCalledWith(
+      expect.stringContaining('/assignments/42'),
+      expect.any(Object)
+    );
+  });
+
+  it('sets product assignments using the expected payload wrapper', () => {
+    (http.post as jest.Mock).mockReturnValue(of({ status: true, roles: [], data: [] }));
+    const assignments = [{ role: 'creative_designer' as const, userId: 7 }];
+
+    service.setProductAssignments(42, assignments);
+
+    expect(http.post).toHaveBeenCalledWith(
+      expect.stringContaining('/assignments/42'),
+      { assignments },
+      expect.any(Object)
+    );
+  });
+
+  it('clears one product assignment role', () => {
+    (http.delete as jest.Mock).mockReturnValue(of({ status: true, deleted: 1 }));
+
+    service.clearProductAssignment(42, 'salesperson');
+
+    expect(http.delete).toHaveBeenCalledWith(
+      expect.stringContaining('/assignments/42/salesperson'),
+      expect.any(Object)
+    );
+  });
+});
