var openTabs = await chromeBrowser.user.openTabs();
var designTabInfo = openTabs.find(t => t.url && t.url.includes('designflow.app/apps/rfq')) || openTabs.find(t => t.url && t.url.includes('alsand.designflow.app'));
var chromeTab = await chromeBrowser.user.claimTab(designTabInfo);
await chromeTab.playwright.waitForLoadState({ state: 'domcontentloaded', timeoutMs: 15000 }).catch(() => {});
await chromeTab.playwright.waitForTimeout(2000);
var chromeInfo = await chromeTab.playwright.evaluate(() => ({
  title: document.title,
  url: location.href,
