    private azureSso: AzureSsoService,
    private authGuard: AuthGuard,
    private _service: NotificationsService
  ) {

  }

  async ngOnInit() {
    this.form = this.fb.group({
      email: this.emailFormControl,
      passw: ['', Validators.required],
      remember: [false]
    });
    let form = document.getElementById('form');
    if (localStorage.getItem('token')) {
      let isValid = await this.authGuard.canActivate()
      if (isValid) {
        this.router.navigate(['/apps/rfq']);
      } else {
        form.style.visibility = 'visible';
      }
    } else {
      form.style.visibility = 'visible';
    }
  }

  async send() {
    if (this.form.value.email && this.form.value.passw) {
      if (this.emailFormControl.valid) {
        try {
          const data: any = await firstValueFrom(this.itemService.getUserLoginInfo(this.form.value));
          if (data) {
            if (data.status == 'success') {
              await this._onLoginSuccess(data.token);
            } else {
              this.snackbar.open('The username or password is incorrect.', 'OK', {
                duration: 5000
              });
            }
          }
        } catch (err) {
          console.error('[Login] send() failed:', err);
        }
      } else {
        this.snackbar.open('The email is not a valid email address.', 'OK', {
          duration: 5000
        });
      }
    } else {
      this.snackbar.open('Please fill all the fields.', 'OK', {
        duration: 5000
      });
    }
  }

  /** Opens the Microsoft login popup and exchanges the Azure ID token for a Designflow JWT. */
  async loginWithMicrosoft(): Promise<void> {
    this.microsoftLoading = true;
    this.cd.markForCheck();
    try {
      const idToken = await this.azureSso.loginPopup();
      const data = await firstValueFrom(this.itemService.loginWithAzure(idToken));
      if (data?.status === 'success') {
        await this._onLoginSuccess(data.token);
      } else {
        this.snackbar.open('Microsoft sign-in failed. Please try again.', 'OK', { duration: 5000 });
      }
    } catch (err: any) {
      // user_cancelled is a normal flow — don't show an error
      if (err?.errorCode !== 'user_cancelled' && err?.message !== 'user_cancelled') {
        console.error('[Login] loginWithMicrosoft() failed:', err);
        this.snackbar.open('Microsoft sign-in failed. Please try again.', 'OK', { duration: 5000 });
      }
    } finally {
      this.microsoftLoading = false;
      this.cd.markForCheck();
    }
  }

  /** Persists the JWT and navigates into the app, then loads notifications. */
  private async _onLoginSuccess(token: string): Promise<void> {
    localStorage.setItem('token', token);
    await this.router.navigate(['/apps/rfq']);
    this.itemService.getnotifications().subscribe((res: any) => {
      if (res.status) {
        res.data.forEach((element) => {
          const notification = this._service[element.type](element.title, element.message, {
            timeOut: 5000,
            showProgressBar: true,
            pauseOnHover: true,
            clickToClose: true,
            maxLength: 10,
          });
          notification.click.subscribe(async () => {
            try {
              await firstValueFrom(this.itemService.markNotificationAsRead({ id: element.id }));
            } catch (err) {
              console.error('[Login] markNotificationAsRead failed:', err);
            }
          });
        });
      }
    });
  }

  toggleVisibility() {
    if (this.visible) {
      this.inputType = 'password';
      this.visible = false;
      this.cd.markForCheck();
    } else {
      this.inputType = 'text';
      this.visible = true;
      this.cd.markForCheck();
    }
  }
