const sql = require('../models/db');

const PRODUCT_ASSIGNMENT_ROLES = Object.freeze([
  'creative_designer',
  'creative_director',
  'technical_designer',
  'licensing_person',
  'salesperson',
]);

const ROLE_SET = new Set(PRODUCT_ASSIGNMENT_ROLES);

function toInteger(value) {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isInteger(parsed) ? parsed : null;
}

function makeError(message, statusCode = 400) {
  const err = new Error(message);
  err.statusCode = statusCode;
  return err;
}

function normalizeAssignments(input) {
  const rawAssignments = Array.isArray(input)
    ? input
    : Object.entries(input || {}).map(([role, value]) => ({
        role,
        userId: typeof value === 'object' && value !== null
          ? value.userId ?? value.user_id_fk
          : value,
      }));

  return rawAssignments.map((assignment) => {
    const role = String(assignment.role || '').trim();
    if (!ROLE_SET.has(role)) {
      throw makeError(`Invalid product assignment role: ${role}`);
    }

    return {
      role,
      userId: toInteger(assignment.userId ?? assignment.user_id_fk),
    };
  });
}

async function assertItemExists(itemId) {
  const item = await sql.itemHeader.findByPk(itemId);
  if (!item) {
    throw makeError(`Item ${itemId} was not found.`, 404);
  }
}

async function assertUserExists(userId) {
  const user = await sql.users.findByPk(userId);
  if (!user) {
    throw makeError(`User ${userId} was not found.`, 400);
  }
}

const ProductAssignmentService = {};

ProductAssignmentService.roles = PRODUCT_ASSIGNMENT_ROLES;

ProductAssignmentService.getAssignments = async (itemId) => {
  const normalizedItemId = toInteger(itemId);
  if (!normalizedItemId) {
    throw makeError('A valid item id is required.');
  }

  return sql.productUserAssignment.findAll({
    where: { item_id_fk: normalizedItemId },
    include: [{
      model: sql.users,
      as: 'user',
      attributes: ['id', 'name', 'lastname', 'email', 'profile_photo', 'level'],
    }],
    order: [['role', 'ASC']],
  });
};

ProductAssignmentService.setAssignments = async (itemId, assignments, actorUserId = null) => {
  const normalizedItemId = toInteger(itemId);
  if (!normalizedItemId) {
    throw makeError('A valid item id is required.');
  }

  await assertItemExists(normalizedItemId);
  const normalizedAssignments = normalizeAssignments(assignments);
  const actorId = toInteger(actorUserId);

  for (const assignment of normalizedAssignments) {
    if (!assignment.userId) {
      await sql.productUserAssignment.destroy({
        where: {
          item_id_fk: normalizedItemId,
          role: assignment.role,
        },
      });
      continue;
    }

    await assertUserExists(assignment.userId);

    const existing = await sql.productUserAssignment.findOne({
      where: {
        item_id_fk: normalizedItemId,
        role: assignment.role,
      },
    });

    const now = new Date();
    if (existing) {
      await existing.update({
        user_id_fk: assignment.userId,
        updated_by_fk: actorId,
        updated_date: now,
      });
    } else {
      await sql.productUserAssignment.create({
        item_id_fk: normalizedItemId,
        role: assignment.role,
        user_id_fk: assignment.userId,
        created_by_fk: actorId,
        created_date: now,
        updated_by_fk: actorId,
        updated_date: now,
      });
    }
  }

  return ProductAssignmentService.getAssignments(normalizedItemId);
};

ProductAssignmentService.clearAssignment = async (itemId, role) => {
  const normalizedItemId = toInteger(itemId);
  if (!normalizedItemId) {
    throw makeError('A valid item id is required.');
  }
  if (!ROLE_SET.has(role)) {
    throw makeError(`Invalid product assignment role: ${role}`);
  }

  return sql.productUserAssignment.destroy({
    where: {
      item_id_fk: normalizedItemId,
      role,
    },
  });
};

module.exports = ProductAssignmentService;

