// Designflow Brand Tokens
$primary: #D81B60;
$dark-slate: #1a202e;
$soft-grey: #f8f9fa;
$text-secondary: #546e7a;
$border-color: #e9ecef;
$border-radius: 6px;
$error: #D32F2F;

:host {
  display: block;
}

.designflow-modal-container {
  display: flex;
  flex-direction: column;
  height: auto;
  max-height: calc(100vh - 48px);
  width: 100%;
  background: white;
  border-radius: $border-radius;
  overflow: hidden;

  // 1. Header (Barbell)
  .modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 20px;
    background: white;
    border-bottom: 1px solid $border-color;
    flex-shrink: 0;

    h3 {
      margin: 0;
      font-size: 20px;
      font-weight: 600;
      color: $dark-slate;
    }
  }

  // 2. Content (Scrollable)
  .modal-content {
    flex-grow: 1;
    min-height: 0;
    overflow-y: auto;
    overflow-x: hidden;
    padding: 18px 20px;

    // Main layout grid
    .form-grid {
      display: grid;
      grid-template-columns: repeat(3, minmax(220px, 300px));
      gap: 14px 20px;
      align-items: end;
      margin-bottom: 16px;
      justify-content: start;

      &.two-col {
        grid-template-columns: repeat(2, minmax(280px, 520px));
      }

      &.one-col {
        grid-template-columns: minmax(320px, 720px);
      }
    }

    // Label Styling
    .mg-field {
      display: flex;
      flex-direction: column;
      gap: 6px;
      width: 100%;

      .label-with-icon {
        font-size: 13px;
        color: $dark-slate;
        font-weight: 500;
        display: flex;
        align-items: center;
        gap: 4px;
        white-space: nowrap;
      }
    }

    // Input Styling
    mat-form-field {
      width: 100%;

      ::ng-deep .mat-mdc-form-field-subscript-wrapper {
        display: none;
      }

      ::ng-deep .mat-mdc-text-field-wrapper {
        height: 48px;
        padding: 0;
        background-color: white;
      }

      ::ng-deep .mat-mdc-form-field-flex {
        height: 48px;
        align-items: center;
        padding: 0 12px;
      }

      ::ng-deep .mat-mdc-form-field-infix {
        padding: 0 !important;
        min-height: unset !important;
        height: 48px;
        display: flex;
        align-items: center;
        border-top: 0;
      }

      input {
        margin-top: 0;
        font-size: 14px;
      }

      &.tags-form-field {
        ::ng-deep .mat-mdc-text-field-wrapper {
          height: auto;
          min-height: 48px;
          padding: 4px 0;
        }

        ::ng-deep .mat-mdc-form-field-flex {
          height: auto;
          flex-wrap: wrap;
          padding: 4px 12px;
        }

        ::ng-deep .mat-mdc-form-field-infix {
          height: auto;
          min-height: 40px !important;
        }

        input {
          min-width: 250px;
          flex-grow: 1;
        }
      }
    }

    // Info Icon Tooltips
    .info-icon {
      color: #3F51B5;
      font-size: 16px;
      width: 16px;
      height: 16px;
      cursor: default;
      opacity: 0.9;
      margin-left: 2px;
    }

    .item-type-section {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    .item-type-header {
      display: grid;
      grid-template-columns: minmax(320px, 720px) auto;
      gap: 16px;
      align-items: end;
      justify-content: start;
    }

    .item-type-create-btn {
      height: 48px;
    }

    .item-type-preview-card {
      display: grid;
      grid-template-columns: 72px minmax(0, 1fr) auto;
      gap: 16px;
      align-items: center;
      padding: 14px 16px;
      border: 1px solid $border-color;
      border-radius: 10px;
      background: $soft-grey;
    }

    .item-type-thumb {
      width: 72px;
      height: 72px;
      border-radius: 8px;
      object-fit: cover;
      border: 1px solid $border-color;
    }

    .item-type-copy {
      display: flex;
      flex-direction: column;
      gap: 6px;
      min-width: 0;
    }

    .item-type-name {
      font-size: 15px;
      font-weight: 600;
      color: $dark-slate;
    }

    .item-type-description {
      color: $text-secondary;
      font-size: 13px;
      line-height: 1.5;
      white-space: pre-wrap;
    }

    ::ng-deep .item-type-option .mdc-list-item__primary-text {
      width: 100%;
    }

    .item-type-option-content {
      display: grid;
      grid-template-columns: 48px minmax(0, 1fr);
      gap: 12px;
      align-items: start;
      width: 100%;
      padding: 6px 0;
    }

    .optional-team-grid {
      grid-template-columns: repeat(3, minmax(180px, 240px));
      justify-content: start;
      align-items: end;
      gap: 14px 16px;
      padding: 12px 14px;
      border: 1px solid $border-color;
      border-radius: $border-radius;
      background: $soft-grey;

      mat-form-field {
        width: 100%;
      }
    }

    .item-type-option-thumb {
      width: 48px;
      height: 48px;
      border-radius: 8px;
      object-fit: cover;
      border: 1px solid $border-color;
      background: white;
    }

    .item-type-option-thumb.placeholder {
      display: flex;
      align-items: center;
      justify-content: center;
      color: $text-secondary;
      background: $soft-grey;
    }

    .item-type-option-copy {
      display: flex;
      flex-direction: column;
      gap: 4px;
      min-width: 0;
    }

    .item-type-option-name {
      font-size: 14px;
      font-weight: 600;
      color: $dark-slate;
      line-height: 1.3;
    }

    .item-type-option-description {
      font-size: 12px;
      line-height: 1.45;
      color: $text-secondary;
      white-space: normal;
    }
  }

  // 3. Footer (Sticky)
  .modal-footer {
    flex-shrink: 0;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 24px;
    background: white;
    border-top: 1px solid $border-color;

    .footer-left {
      display: flex;
      align-items: center;
      gap: 16px;

      .image-preview {
        width: 48px;
        height: 48px;
        border-radius: 4px;
        object-fit: cover;
        border: 1px solid $border-color;
      }
    }

    .footer-actions {
      display: flex;
      gap: 12px;
    }
  }
}

::ng-deep .create-new-item-dialog {
  .mat-mdc-dialog-container,
  .mat-mdc-dialog-surface {
    max-height: calc(100vh - 48px);
    overflow: hidden;
  }
}

// Tooltip background color
::ng-deep .mat-mdc-tooltip {
  overflow: visible !important;
}

::ng-deep .mat-mdc-tooltip .mdc-tooltip__surface {
  background-color: #3F51B5 !important;
  color: #ffffff !important;
  border-radius: 2px !important;
  font-size: 13px !important;
  padding: 8px 12px !important;
  overflow: visible !important;
  position: relative !important;

  &::after {
    content: '';
    position: absolute;
    bottom: -6px;
    left: 50%;
    transform: translateX(-50%);
    border-width: 6px 6px 0;
    border-style: solid;
    border-color: #3F51B5 transparent transparent;
  }
}

@media (max-width: 900px) {
  .designflow-modal-container .modal-content {
    .form-grid,
    .form-grid.two-col,
    .optional-team-grid {
      grid-template-columns: 1fr;
    }

    .item-type-header,
    .item-type-preview-card {
      grid-template-columns: 1fr;
    }
  }
}

// -------------------------------------------------------------------------
// TABLE-STYLE DROPDOWN (Global)
// -------------------------------------------------------------------------
::ng-deep .mat-mdc-autocomplete-panel {
  padding: 0 !important;
  min-width: 320px !important;
  overflow-x: auto !important; // ENABLE HORIZONTAL SCROLL

  // The Header Row Container (Material Group Label Override)
  .mat-mdc-optgroup-label {
    padding: 0 !important;
    width: 100%;
    display: block;
  }

  // Default Option (Data Rows)
  .mat-mdc-option {
    padding: 0 !important;
    min-height: 40px;
    height: 40px;
    border-bottom: 1px solid #f0f0f0;
    width: 100%; // Ensure option takes full width

    &:last-child {
      border-bottom: none;
    }
  }

  // The Inner Header Container
    .dropdown-header-container {
    position: sticky;
    top: 0;
    z-index: 100;
    background: white;
    border-bottom: 1px solid #e9ecef;
    height: 40px;
    display: block;
    width: 100%;
    min-width: 0;
  }

  // Shared "Table Row" Flex Layout
    .dropdown-div {
      display: flex;
      align-items: stretch;
      width: 100%;
      height: 100%;
      font-size: 13px;

    // Column 1: Code (Strictly applied only when NOT single-col)
    &:not(.single-col) span:first-child {
      flex: 0 0 80px;
      text-align: center;
      font-weight: 600;
      border-right: 1px solid #e9ecef;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 0 8px;
      color: $dark-slate;
    }

    // Column 2: Description (or Single Column content)
      .dropdown-desc,
      .season-dropdown-width:last-child {
      flex: 1 1 auto;
      min-width: 0;
      padding: 0 12px;
      display: flex;
      align-items: center;
      justify-content: flex-start;
      color: $dark-slate;
      white-space: nowrap;
    }

    // Special case: Single Column content (For Customer)
    &.single-col {
      span {
        border-right: none;
        flex: 1 1 auto;
        justify-content: flex-start; // Align left for simple lists
        padding: 0 16px;
        white-space: nowrap;
      }
    }

    // HEADER ROW SPECIFIC STYLES
    &.header-row {
      background-color: #f8f9fa;

      // Header for Code Column
      &:not(.single-col) span:first-child {
        font-weight: 700;
        background-color: #f8f9fa;
        justify-content: center;
        display: flex;
      }

      // Header for Desc Column
      .dropdown-desc,
      .season-dropdown-width:last-child {
        font-weight: 700;
        background-color: #f8f9fa;
        justify-content: center;
        display: flex;
      }
    }

    .season-dropdown-width:first-child {
      flex: 0 0 100px;
      border-right: 1px solid #e9ecef;
      display: flex;
      align-items: center;
      justify-content: center;
    }
  }
}

// Button Overrides
button[mat-stroked-button] {
  border-color: $border-color !important;
  color: $text-secondary !important;
  height: 48px;
  border-radius: $border-radius;
  font-weight: 500;

  &:hover {
    border-color: $dark-slate !important;
    color: $dark-slate !important;
    background: $soft-grey;
  }
}

button[mat-flat-button] {
  background-color: $primary !important;
  color: white !important;
  height: 48px;
  border-radius: $border-radius;
  font-weight: 500;

  &:disabled {
    background-color: rgba(0, 0, 0, 0.12) !important;
    color: rgba(0, 0, 0, 0.38) !important;
  }
}

